using UnityEngine;using UnityEngine.UI;using System.Collections;
public class DangerZoneUI : MonoBehaviour{public static DangerZoneUI Instance{get;private set;}public enum DangerLevel{Safe,Caution,Warning,Critical}[SerializeField]private CanvasGroup redVignette;[SerializeField]private GameObject warningIcon;[SerializeField]private Image edgeL,edgeR;private DangerLevel cur;private Coroutine hb;private void Awake(){if(Instance==null)Instance=this;else Destroy(gameObject);}public void SetDangerLevel(DangerLevel l){if(l==cur)return;cur=l;if(redVignette)redVignette.alpha=0;if(warningIcon)warningIcon.SetActive(false);if(hb!=null)StopCoroutine(hb);switch(l){case DangerLevel.Safe:SG(Color.clear);break;case DangerLevel.Caution:SG(new Color(1,.5f,0,.3f));break;case DangerLevel.Warning:SG(new Color(1,.2f,0,.5f));if(warningIcon)warningIcon.SetActive(true);break;case DangerLevel.Critical:SG(new Color(1,0,0,.8f));if(warningIcon)warningIcon.SetActive(true);hb=StartCoroutine(HB());break;}}private void SG(Color c){if(edgeL)edgeL.color=c;if(edgeR)edgeR.color=c;}private IEnumerator HB(){while(true){float b=Mathf.Abs(Mathf.Sin(Time.time*2*Mathf.PI));if(redVignette)redVignette.alpha=b*0.6f;SG(new Color(1,0,0,Mathf.Lerp(0.3f,1,b)));yield return null;}}}